"use client";

import React, { useEffect, useState } from "react";
import { Search, ChevronDown, Eye, Filter, Clock } from "lucide-react";
import { useRouter } from "next/navigation";

const ClaimReviewDashboard = () => {
  const [claims, setClaims] = useState([]);
  const [loading, setLoading] = useState(true);

  const [searchTerm, setSearchTerm] = useState("");
  const [filterStatus, setFilterStatus] = useState("All");

  const router = useRouter();

  // ================= FETCH CLAIMS =================
  useEffect(() => {
    const fetchClaims = async () => {
      try {
        const token = localStorage.getItem("accessToken");
        const res = await fetch("http://localhost:5000/admin/pendingClaims", {
          method: "GET",
          headers: {
            Authorization: `Bearer ${token}`,
          },
        });
        if (!res.ok) throw new Error("Failed to fetch claims");
        const data = await res.json();
        setClaims(data);
      } catch (error) {
        console.error("Error fetching claims:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchClaims();
  }, []);

  // ================= FILTER LOGIC =================
  const filteredClaims = claims.filter((claim) => {
    const search = searchTerm.toLowerCase();

    const matchesSearch =
      claim._id.toLowerCase().includes(search) ||
      claim.itemId?.itemName.toLowerCase().includes(search) ||
      claim.claimedBy?.name.toLowerCase().includes(search);

    const matchesStatus =
      filterStatus === "All" ||
      claim.status.toLowerCase() === filterStatus.toLowerCase();

    return matchesSearch && matchesStatus;
  });

  // ================= UI =================
  if (loading) {
    return (
      <div className="p-10 text-center text-lg font-semibold">
        Loading Claims...
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 p-8">
      <h1 className="text-3xl font-extrabold text-gray-900 border-b pb-3 mb-6">
        Claim Review Dashboard 📝
      </h1>

      {/* ================= FILTER + SEARCH ================= */}
      <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-white rounded-lg shadow border">
        {/* Search */}
        <div className="relative flex-grow">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400" />
          <input
            type="text"
            placeholder="Search by Claim ID, Item, or Claimant..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-indigo-500 focus:border-indigo-500"
          />
        </div>

        {/* Status Filter */}
        <div className="relative w-full md:w-56">
          <Filter className="absolute left-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400" />
          <select
            value={filterStatus}
            onChange={(e) => setFilterStatus(e.target.value)}
            className="w-full pl-10 pr-8 py-2 border rounded-lg appearance-none bg-white focus:ring-indigo-500 focus:border-indigo-500"
          >
            <option value="All">All Status</option>
            <option value="pending">Pending</option>
            <option value="approved">Approved</option>
            <option value="rejected">Rejected</option>
          </select>
          <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 h-5 w-5 text-gray-400 pointer-events-none" />
        </div>
      </div>

      {/* ================= TABLE ================= */}
      <div className="bg-white shadow-lg rounded-xl overflow-hidden">
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-100">
            <tr>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">
                Claim ID
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">
                Item
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">
                Claimant
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">
                Date
              </th>
              <th className="px-6 py-3 text-center text-xs font-medium text-gray-500 uppercase">
                Status
              </th>
              <th className="px-6 py-3"></th>
            </tr>
          </thead>

          <tbody className="divide-y">
            {filteredClaims.length > 0 ? (
              filteredClaims.map((claim) => (
                <tr key={claim._id} className="hover:bg-indigo-50 transition">
                  {/* Claim ID */}
                  <td className="px-6 py-4 text-sm font-semibold text-indigo-600">
                    {claim._id.slice(-6)}
                  </td>

                  {/* Item */}
                  <td className="px-6 py-4 text-sm">
                    {claim.itemId?.itemName}
                    <span className="text-xs text-gray-500">
                      {" "}
                      ({claim.itemId?._id.slice(-6)})
                    </span>
                  </td>

                  {/* Claimant */}
                  <td className="px-6 py-4 text-sm">{claim.claimedBy?.name}</td>

                  {/* Date */}
                  <td className="px-6 py-4 text-sm text-gray-500">
                    {new Date(claim.createdAt).toLocaleString()}
                  </td>

                  {/* Status */}
                  <td className="px-6 py-4 text-center">
                    <span className="px-3 py-1 text-xs rounded-full border bg-yellow-100 text-yellow-800 inline-flex items-center gap-1">
                      <Clock size={12} /> {claim.status}
                    </span>
                  </td>

                  {/* Action */}
                  <td className="px-6 py-4 text-right">
                    <button
                      onClick={() =>
                        router.push(`/admin/claimsreview/${claim._id}`)
                      }
                      className="inline-flex items-center gap-1 px-3 py-1.5 bg-indigo-600 text-white rounded-md hover:bg-indigo-700"
                    >
                      <Eye size={16} />
                      View
                    </button>
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="6" className="py-10 text-center text-gray-500">
                  No claims found.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default ClaimReviewDashboard;
